import{_ as t,o,c as n,a3 as i}from"./chunks/framework.BveOjhN0.js";const m=JSON.parse('{"title":"Meetings — Developer Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Meetings — Developer Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/meetings"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Meetings — Developer Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/meetings"}]]},"headers":[],"relativePath":"developer-guide/meetings.md","filePath":"developer-guide/meetings.md","lastUpdated":1784746021000}'),d={name:"developer-guide/meetings.md"};function r(a,e,c,s,l,g){return o(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="meetings-—-developer-guide" tabindex="-1">Meetings — Developer Guide <a class="header-anchor" href="#meetings-—-developer-guide" aria-label="Permalink to &quot;Meetings — Developer Guide&quot;">​</a></h1><blockquote><p><strong>Status: Implemented</strong><br> Required dependency: Calendar. Meetings owns booking, host, attendees, providers, and reminders; Calendar owns the projected event.</p></blockquote><h2 id="ownership" tabindex="-1">Ownership <a class="header-anchor" href="#ownership" aria-label="Permalink to &quot;Ownership&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concept</th><th>Owner</th></tr></thead><tbody><tr><td><code>meetings</code>, attendees, reminders, provider connections</td><td>Meetings module</td></tr><tr><td>Zoom / Google Meet OAuth + remote meeting sync</td><td>Meetings module</td></tr><tr><td>Calendar projection (<code>source=meeting</code>)</td><td><code>CalendarEventService::upsertFromSource</code></td></tr></tbody></table><h2 id="domain" tabindex="-1">Domain <a class="header-anchor" href="#domain" aria-label="Permalink to &quot;Domain&quot;">​</a></h2><ul><li><code>App\\Models\\Meeting</code> — <code>BelongsToTenant</code>, <code>LogsActivity</code>, <code>SoftDeletes</code></li><li><code>MeetingAttendee</code> — internal <code>user_id</code> and/or external <code>email</code>/<code>name</code></li><li><code>MeetingProviderConnection</code> — encrypted tokens, one connection per provider per tenant</li><li><code>MeetingReminder</code> — single durable reminder row per meeting</li></ul><p>Enums: <code>MeetingStatusEnum</code>, <code>MeetingProviderEnum</code>, <code>MeetingAttendeeRoleEnum</code>, <code>MeetingProviderConnectionStatusEnum</code>, <code>MeetingReminderStatusEnum</code>, <code>MeetingProviderSyncStatusEnum</code>.</p><p>Morph alias: <code>meeting</code> → <code>App\\Models\\Meeting</code> (registered in <code>AppServiceProvider</code>).</p><h2 id="service-contract" tabindex="-1">Service contract <a class="header-anchor" href="#service-contract" aria-label="Permalink to &quot;Service contract&quot;">​</a></h2><p><code>App\\Services\\Tenant\\MeetingService</code> is the sole writer:</p><ul><li>CRUD, cancel, assign host, attendee sync</li><li>Provider sync via <code>MeetingProviderRegistry</code> (<code>none</code> / Zoom / Google Meet; fake drivers in testing)</li><li>Calendar projection / cancel / delete</li><li>Reminder schedule / reschedule / cancel</li></ul><h2 id="providers" tabindex="-1">Providers <a class="header-anchor" href="#providers" aria-label="Permalink to &quot;Providers&quot;">​</a></h2><ul><li>Interface: <code>App\\Contracts\\Meetings\\MeetingProviderInterface</code> (authorize, exchange, <strong>refreshAccessToken</strong>, create/update/delete)</li><li>Registry: <code>App\\Services\\Meetings\\MeetingProviderRegistry</code></li><li><strong>Per-tenant BYOK:</strong> each workspace stores its own OAuth <code>client_id</code> / <code>client_secret</code> / optional <code>webhook_secret</code> (encrypted) on <code>MeetingProviderConnection</code></li><li>OAuth account connect: <code>MeetingIntegrationController</code> (<code>meetings.manage_integrations</code>) with one-time cache nonce in <code>state</code></li><li>Platform-hosted callback: <code>GET /api/oauth/meetings/{provider}/callback</code> (tenant + nonce from encrypted <code>state</code>; re-checks <code>manage_integrations</code>)</li><li>Access tokens refresh automatically near expiry (Zoom + Google)</li><li><strong>Google Meet</strong> creates a Meet <strong>space</strong> join link (not a Google Calendar conference); update is a no-op; delete removes the space when possible</li><li><strong>Webhooks:</strong> <code>MeetingWebhookController</code> is a <strong>stub</strong> (custom HMAC ack only — not Zoom/Google-native event ingestion). Do not rely on it for production reconciliation yet.</li><li>Retry: <code>RetryProviderSyncJob</code> (tenant id + Laravel <code>$tries</code>/<code>$backoff</code>; does <strong>not</strong> re-dispatch forever from <code>syncProvider</code>)</li></ul><p>Config: <code>config/meetings.php</code> (fake flag + Google/Zoom OAuth scopes + callback path only — <strong>no platform client secrets</strong>). Fake drivers are forced off in <code>production</code>. Prefer fail-closed on create when provider ≠ <code>none</code> and account is not connected. Remote provider delete on cancel/delete is best-effort (local status always wins; failures land on sanitized <code>provider_sync_*</code>). Manual retry: <code>POST /meetings/{id}/retry-sync</code>.</p><h2 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Channels</th></tr></thead><tbody><tr><td><code>meeting.invite</code> / <code>meeting.updated</code> / <code>meeting.cancelled</code></td><td>mail + database + broadcast + web push (users); mail-only for external guests</td></tr><tr><td><code>meeting.reminder</code></td><td>same; dispatched by <code>crm:send-due-notifications</code></td></tr></tbody></table><p>Subscriber: <code>MeetingEventSubscriber</code> (audit + notifications; skips actor for invite/update/cancel).</p><h2 id="scheduler" tabindex="-1">Scheduler <a class="header-anchor" href="#scheduler" aria-label="Permalink to &quot;Scheduler&quot;">​</a></h2><p><code>crm:send-due-notifications</code> (every 5 minutes, <code>withoutOverlapping</code>, <code>onOneServer</code>) claims due <code>MeetingReminder</code> rows atomically (<code>pending</code> → <code>sending</code> → <code>sent</code>) with <code>NotificationIdempotency</code> for users and cache dedupe for external guest mail.</p><h2 id="frontend" tabindex="-1">Frontend <a class="header-anchor" href="#frontend" aria-label="Permalink to &quot;Frontend&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Piece</th><th>Location</th></tr></thead><tbody><tr><td>Page</td><td><code>src/pages/meetings/meetings-page.tsx</code></td></tr><tr><td>Form / detail / integrations</td><td><code>meeting-form-dialog.tsx</code>, <code>meeting-detail-sheet.tsx</code>, <code>meeting-integrations-panel.tsx</code></td></tr><tr><td>API</td><td><code>meetingService</code> in <code>src/api/services.ts</code></td></tr><tr><td>Notifications</td><td><code>src/notifications/modules/meetings.ts</code></td></tr><tr><td>E2E</td><td><code>e2e/tests/meetings/</code>, <code>npm run test:e2e:meetings</code></td></tr></tbody></table><p>Provider options in the form are disabled until Integrations reports <code>connected</code>. Calendar projections link back to Meetings and are read-only on the Calendar sheet.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>Grants</th></tr></thead><tbody><tr><td>admin</td><td>all including <code>view_all</code>, <code>assign_host</code>, <code>manage_integrations</code></td></tr><tr><td>manager</td><td>view/create/update/<code>view_all</code>/<code>assign_host</code> (no delete / manage_integrations)</td></tr><tr><td>staff</td><td>view/create/update/delete (scoped); no <code>view_all</code> / <code>manage_integrations</code></td></tr></tbody></table><h2 id="registration-migrate-only" tabindex="-1">Registration (migrate-only) <a class="header-anchor" href="#registration-migrate-only" aria-label="Permalink to &quot;Registration (migrate-only)&quot;">​</a></h2><ul><li><code>2026_07_22_000000_create_meetings_tables.php</code></li><li><code>2026_07_22_000001_register_meetings_module.php</code></li><li><code>2026_07_22_000002_add_meetings_permissions.php</code></li><li><code>2026_07_22_000003_add_meetings_calendar_dependency.php</code></li></ul><p>Also listed in <code>CatalogSeeder</code> for fresh/local/CI.</p><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><ul><li>Pest: <code>tests/Feature/Tenant/Meeting/*</code></li><li>Playwright: <code>npm run test:e2e:meetings</code></li></ul><h2 id="explicit-non-goals-current" tabindex="-1">Explicit non-goals (current) <a class="header-anchor" href="#explicit-non-goals-current" aria-label="Permalink to &quot;Explicit non-goals (current)&quot;">​</a></h2><ul><li>Per-user personal Zoom/Google accounts</li><li>Multiple reminders per meeting</li><li>Changing Calendar ACLs so invitees see projected events (Meetings list remains invitee source of truth)</li></ul>',31)])])}const h=t(d,[["render",r]]);export{m as __pageData,h as default};
